+  type InferRecursiveInput,
+  type InferRecursiveIssue,
+  type InferRecursiveOutput,
+  type RecurSchema,
+} from './types.ts';
+
+/**
+ * Recursive schema interface.
+ */
+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    InferRecursiveInput<TWrapped>,
+    InferRecursiveOutput<TWrapped>,
+    InferRecursiveIssue<TWrapped>
+  > {
+  /**
+   * The schema type.
+   */
+  readonly type: 'recursive';
+  /**
+   * The schema reference.
+   */
+  readonly reference: typeof recursive;
+  /**
+   * The wrapped schema.
+   */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * Creates a recursive schema by resolving `Recur` placeholders.
+ *
+ * @param schema The schema to be made recursive.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(schema: TSchema): RecursiveSchema<TSchema> {
+  const recursiveSchema = {
+    kind: 'schema' as const,
+    type: 'recursive' as const,
+    reference: recursive,
+    expects: schema.expects,
+    async: false as const,
+    wrapped: undefined as unknown as TSchema,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
+      return this.wrapped['~run'](dataset, config);
+    },
+  } satisfies Omit<
+    RecursiveSchema<TSchema>,
+    'wrapped' | '~types' | '~run'
+  > & {
+    wrapped: TSchema;
+    '~run': (
+      dataset: UnknownDataset,
+      config: Config<BaseIssue<unknown>>
+    ) => OutputDataset<InferRecursiveOutput<TSchema>, InferRecursiveIssue<TSchema>>;
+  };
+  recursiveSchema.wrapped = _resolveRecur(schema, recursiveSchema) as TSchema;
+  return recursiveSchema;
+}
+
+/**
+ * Resolves recursive placeholders in a schema graph.
+ *
+ * @internal
+ */
+export function _resolveRecur<TValue>(
+  value: TValue,
+  recursiveSchema: RecurSchema,
+  values = new Map<object, unknown>()
+): TValue {
+  if (value === Recur) {
+    return recursiveSchema as TValue;
+  }
+  if (Array.isArray(value)) {
+    return value.map((item) => _resolveRecur(item, recursiveSchema, values)) as TValue;
+  }
+  if (value && typeof value === 'object') {
+    const cached = values.get(value);
+    if (cached) {
+      return cached as TValue;
+    }
+    const descriptors = Object.getOwnPropertyDescriptors(value);
+    const clone = Object.create(Object.getPrototypeOf(value));
+    values.set(value, clone);
+    for (const descriptor of Object.values(descriptors)) {
+      if ('value' in descriptor) {
+        descriptor.value = _resolveRecur(descriptor.value, recursiveSchema, values);
+      }
+    }
+    Object.defineProperties(clone, descriptors);
+    return clone;
+  }
+  return value;
+}
